// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section id=\"from-vanilla-to-django-postgresql\">\n<div>The Definitive Developer Guide</div>\n<h1>From Vanilla to <em>Django</em> &amp; PostgreSQL</h1>\n<p>A deep, philosophical walkthrough of how Django thinks, how PostgreSQL works, and how to wire them together into production-grade web applications \u2014 from first principles.</p>\n<div>\n<span class=\"pill tone-success\"> Django 5.x</span>\n<span class=\"pill tone-info\"> PostgreSQL 16</span>\n<span class=\"pill tone-tip\"> Python 3.12+</span>\n<span class=\"pill\">ORM Deep Dive</span>\n<span class=\"pill\">Migrations</span>\n<span class=\"pill\">QuerySets</span>\n<span class=\"pill\">N+1 Solutions</span>\n<span class=\"pill\">Transactions</span>\n</div>\n</section>\n<section data-section=\"\" id=\"philosophy\">\n<div class=\"section-header\"><div class=\"section-num\">01</div><div>\n<div class=\"section-title\">The Philosophy</div>\n<div class=\"section-subtitle\">Why Django thinks the way it does</div>\n</div></div>\n<div class=\"philosophy-block\">\n Don't repeat yourself. Make it explicit. Keep it pragmatic. The database is not an implementation detail \u2014 it is the heart of your application.\n <span>Django's Design Tenets</span>\n</div>\n<p>When you come from vanilla PHP, raw JavaScript, or Flask, Django can feel like it's doing too much for you. That feeling is the point. Django is built around the idea that a web application has <strong>solved problems</strong> \u2014 authentication, form validation, SQL generation, URL routing \u2014 and you shouldn't have to solve them again.</p>\n<p>But Django isn't magic. It's a collection of very deliberate choices. To use it well, you need to understand the reasoning behind those choices, not just the syntax.</p>\n<h2>The MVC pattern \u2014 and why Django calls it MTV</h2>\n<p>You've probably heard of Model-View-Controller. Django implements the same idea but renames the pieces to better reflect what they do in a web context:</p>\n<div>\n<svg viewbox=\"0 0 680 200\" xmlns=\"http://www.w3.org/2000/svg\">\n<defs><marker id=\"a\" markerheight=\"6\" markerwidth=\"6\" orient=\"auto-start-reverse\" refx=\"8\" refy=\"5\" viewbox=\"0 0 10 10\"><path d=\"M2 1L8 5L2 9\" fill=\"none\" stroke=\"#6b6760\" stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"1.5\"></path></marker></defs>\n<rect fill=\"#1a1917\" height=\"56\" rx=\"8\" stroke=\"#3a3835\" stroke-width=\"1\" width=\"90\" x=\"10\" y=\"72\"></rect>\n<text fill=\"#7dd8a0\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"55\" y=\"97\">Browser</text>\n<text fill=\"#5c5952\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"55\" y=\"113\">HTTP Request</text>\n<line marker-end=\"url(#a)\" stroke=\"#6b6760\" stroke-width=\"1\" x1=\"100\" x2=\"128\" y1=\"100\" y2=\"100\"></line>\n<rect fill=\"#e8f2ec\" height=\"56\" rx=\"8\" stroke=\"#2d6e45\" stroke-width=\"1\" width=\"90\" x=\"130\" y=\"72\"></rect>\n<text fill=\"#1a4a2e\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"175\" y=\"97\">URLconf</text>\n<text fill=\"#3a6e50\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"175\" y=\"113\">urls.py</text>\n<line marker-end=\"url(#a)\" stroke=\"#6b6760\" stroke-width=\"1\" x1=\"220\" x2=\"248\" y1=\"100\" y2=\"100\"></line>\n<rect fill=\"#deeaf7\" height=\"84\" rx=\"8\" stroke=\"#2d5a8e\" stroke-width=\"1.5\" width=\"110\" x=\"250\" y=\"58\"></rect>\n<text fill=\"#1e3a5f\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"305\" y=\"88\">View</text>\n<text fill=\"#2d5a8e\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"305\" y=\"104\">views.py</text>\n<text fill=\"#4a6e9e\" font-family=\"Inter,sans-serif\" font-size=\"9\" text-anchor=\"middle\" x=\"305\" y=\"119\">Business Logic</text>\n<line marker-end=\"url(#a)\" stroke=\"#6b6760\" stroke-dasharray=\"4 3\" stroke-width=\"1\" x1=\"305\" x2=\"305\" y1=\"142\" y2=\"162\"></line>\n<rect fill=\"#ede5f7\" height=\"28\" rx=\"6\" stroke=\"#7a3eb0\" stroke-width=\"1\" width=\"126\" x=\"242\" y=\"164\"></rect>\n<text fill=\"#4a1d6e\" font-family=\"Inter,sans-serif\" font-size=\"10\" font-weight=\"600\" text-anchor=\"middle\" x=\"305\" y=\"182\">Model \u2192 PostgreSQL</text>\n<line marker-end=\"url(#a)\" stroke=\"#6b6760\" stroke-width=\"1\" x1=\"360\" x2=\"388\" y1=\"100\" y2=\"100\"></line>\n<rect fill=\"#f5edd8\" height=\"56\" rx=\"8\" stroke=\"#8b5e2a\" stroke-width=\"1\" width=\"100\" x=\"390\" y=\"72\"></rect>\n<text fill=\"#5c3a1a\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"440\" y=\"97\">Template</text>\n<text fill=\"#8b5e2a\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"440\" y=\"113\">.html files</text>\n<line marker-end=\"url(#a)\" stroke=\"#6b6760\" stroke-width=\"1\" x1=\"490\" x2=\"518\" y1=\"100\" y2=\"100\"></line>\n<rect fill=\"#1a1917\" height=\"56\" rx=\"8\" stroke=\"#3a3835\" stroke-width=\"1\" width=\"100\" x=\"520\" y=\"72\"></rect>\n<text fill=\"#7dd8a0\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"570\" y=\"97\">Response</text>\n<text fill=\"#5c5952\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"570\" y=\"113\">HTML / JSON</text>\n<text fill=\"#a8a49f\" font-family=\"Inter,sans-serif\" font-size=\"10\" letter-spacing=\"0.08em\" text-anchor=\"middle\" x=\"340\" y=\"24\">DJANGO'S MODEL-TEMPLATE-VIEW (MTV) LIFECYCLE</text>\n</svg>\n<div class=\"diagram-caption\">Every HTTP request travels this exact path. Understanding it means understanding Django.</div>\n</div>\n<div class=\"cards\">\n<div class=\"card\"><div class=\"card-icon tone-success\"></div><h4>Model</h4><p>Defines the shape of your data and talks to the database. A <code>User</code>, a <code>Product</code>, an <code>Order</code>. Django translates these Python classes directly into PostgreSQL tables.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-info\"></div><h4>View</h4><p>In Django, a View is a function or class that receives an HTTP request and returns a response. It orchestrates: fetch data from the model, pass it to a template.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-tip\"></div><h4>Template</h4><p>HTML files with Django's template language. They receive context data from the view and render the final HTML. Deliberately logic-light \u2014 no SQL in templates.</p></div>\n</div>\n</section>\n<section data-section=\"\" id=\"setup\">\n<div class=\"section-header\"><div class=\"section-num\">02</div><div>\n<div class=\"section-title\">Project Setup</div>\n<div class=\"section-subtitle\">From zero to a running Django + PostgreSQL environment</div>\n</div></div>\n<div>\n<div class=\"step\"><div class=\"step-num\">1</div><div class=\"step-content\"><h4>Create a virtual environment</h4><p>Always isolate Python dependencies per project. This is non-negotiable \u2014 it prevents version conflicts across projects.</p></div></div>\n</div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Terminal</span><span class=\"code-lang\">bash</span></div><pre><code><span># Create a fresh project directory</span>\nmkdir my_project &amp;&amp; cd my_project\n\n<span># Create isolated Python environment</span>\npython -m venv venv\nsource venv/bin/activate <span># Windows: venv\\Scripts\\activate</span>\n\n<span># Install Django + PostgreSQL adapter + secrets management</span>\npip install django psycopg2-binary python-decouple\n\n<span># Start a new Django project (trailing dot = install in current dir)</span>\ndjango-admin startproject config .\n\n<span># Create your first app</span>\npython manage.py startapp store</code></pre></div>\n<div class=\"callout tone-info\"><div class=\"callout-label\"> What just happened?</div><p><code>django-admin startproject config .</code> creates a <code>config/</code> folder with your project settings, plus <code>manage.py</code> \u2014 the Swiss Army knife of Django commands. The trailing <code>.</code> means \"put it here, don't nest in another folder\".</p></div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Project structure</span><span class=\"code-lang\">tree</span></div><pre><code>my_project/\n\u251c\u2500\u2500 config/\n\u2502 \u251c\u2500\u2500 settings.py <span># \u2190 Core configuration</span>\n\u2502 \u251c\u2500\u2500 urls.py <span># \u2190 Root URL dispatcher</span>\n\u2502 \u251c\u2500\u2500 asgi.py <span># \u2190 Async server gateway</span>\n\u2502 \u2514\u2500\u2500 wsgi.py <span># \u2190 Production server gateway</span>\n\u251c\u2500\u2500 store/ <span># \u2190 Your app</span>\n\u2502 \u251c\u2500\u2500 models.py <span># \u2190 Database models live here</span>\n\u2502 \u251c\u2500\u2500 views.py <span># \u2190 Request handlers</span>\n\u2502 \u251c\u2500\u2500 admin.py <span># \u2190 Admin interface registration</span>\n\u2502 \u251c\u2500\u2500 apps.py <span># \u2190 App configuration</span>\n\u2502 \u2514\u2500\u2500 migrations/ <span># \u2190 Database change history (auto-generated)</span>\n\u251c\u2500\u2500 manage.py\n\u2514\u2500\u2500 .env <span># \u2190 Secrets \u2014 NEVER commit this!</span></code></pre></div>\n<h2>Connecting PostgreSQL</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">PostgreSQL shell (psql)</span><span class=\"code-lang\">sql</span></div><pre><code><span>-- Connect to postgres as superuser</span>\npsql -U postgres\n\n<span>-- Create dedicated user and database</span>\n<span>CREATE USER</span> myuser <span>WITH PASSWORD</span> <span>'secure_password_here'</span>;\n<span>CREATE DATABASE</span> mydb <span>OWNER</span> myuser;\n<span>GRANT ALL PRIVILEGES ON DATABASE</span> mydb <span>TO</span> myuser;</code></pre></div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">config/settings.py \u2014 database config</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> decouple <span>import</span> config\n\nDATABASES = {\n <span>'default'</span>: {\n <span>'ENGINE'</span>: <span>'django.db.backends.postgresql'</span>,\n <span>'NAME'</span>: config(<span>'DB_NAME'</span>),\n <span>'USER'</span>: config(<span>'DB_USER'</span>),\n <span>'PASSWORD'</span>: config(<span>'DB_PASSWORD'</span>),\n <span>'HOST'</span>: config(<span>'DB_HOST'</span>, default=<span>'localhost'</span>),\n <span>'PORT'</span>: config(<span>'DB_PORT'</span>, default=<span>'5432'</span>),\n <span>'CONN_MAX_AGE'</span>: <span>60</span>, <span># persistent connections in production</span>\n }\n}\n\nINSTALLED_APPS = [\n <span>'django.contrib.admin'</span>,\n <span>'django.contrib.auth'</span>,\n <span>'django.contrib.contenttypes'</span>,\n <span>'django.contrib.sessions'</span>,\n <span>'django.contrib.messages'</span>,\n <span>'django.contrib.staticfiles'</span>,\n <span>'django.contrib.postgres'</span>, <span># \u2190 unlock Postgres-specific features</span>\n <span>'store'</span>, <span># \u2190 your app</span>\n]</code></pre></div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">.env (never commit)</span><span class=\"code-lang\">env</span></div><pre><code>SECRET_KEY=your-very-long-secret-key-here-50+chars\nDEBUG=True\nDB_NAME=mydb\nDB_USER=myuser\nDB_PASSWORD=secure_password_here\nDB_HOST=localhost\nDB_PORT=5432</code></pre></div>\n<div class=\"callout tone-tip\"><div class=\"callout-label\"> Pro Tip</div><p>Always use <code>python-decouple</code> or <code>django-environ</code> to load secrets from a <code>.env</code> file. Never hardcode credentials in <code>settings.py</code>. Add <code>.env</code> to your <code>.gitignore</code> immediately. Use different <code>.env</code> files per environment: <code>.env.dev</code>, <code>.env.prod</code>.</p></div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Verify the connection</span><span class=\"code-lang\">bash</span></div><pre><code><span># Run Django's built-in migrations (creates auth tables etc.)</span>\npython manage.py migrate\n\n<span># Create an admin superuser</span>\npython manage.py createsuperuser\n\n<span># Start the development server</span>\npython manage.py runserver\n<span># \u2192 Visit http://127.0.0.1:8000/admin</span></code></pre></div>\n</section>\n<section data-section=\"\" id=\"architecture\">\n<div class=\"section-header\"><div class=\"section-num\">03</div><div>\n<div class=\"section-title\">Django Architecture</div>\n<div class=\"section-subtitle\">The request/response lifecycle \u2014 every layer, explained</div>\n</div></div>\n<p>Every request flows through a series of <strong>middleware</strong> layers, gets routed by the URLconf, processed by a view, and returns a response through those same middleware layers on the way back out. Understanding this pipeline is the difference between debugging by guessing and debugging by knowing.</p>\n<div>\n<svg viewbox=\"0 0 680 380\" xmlns=\"http://www.w3.org/2000/svg\">\n<defs><marker id=\"a2\" markerheight=\"6\" markerwidth=\"6\" orient=\"auto-start-reverse\" refx=\"8\" refy=\"5\" viewbox=\"0 0 10 10\"><path d=\"M2 1L8 5L2 9\" fill=\"none\" stroke=\"#6b6760\" stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"1.5\"></path></marker></defs>\n<text fill=\"#a8a49f\" font-family=\"Inter,sans-serif\" font-size=\"10\" letter-spacing=\"0.1em\" x=\"60\" y=\"36\">REQUEST \u2193</text>\n<text fill=\"#a8a49f\" font-family=\"Inter,sans-serif\" font-size=\"10\" letter-spacing=\"0.1em\" x=\"560\" y=\"36\">\u2191 RESPONSE</text>\n<rect fill=\"#f2f0ec\" height=\"36\" rx=\"6\" stroke=\"#d9d5ce\" stroke-width=\"1\" width=\"170\" x=\"20\" y=\"48\"></rect>\n<text fill=\"#3a3835\" font-family=\"Inter,sans-serif\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"105\" y=\"70\">SecurityMiddleware</text>\n<rect fill=\"#f2f0ec\" height=\"36\" rx=\"6\" stroke=\"#d9d5ce\" stroke-width=\"1\" width=\"170\" x=\"20\" y=\"96\"></rect>\n<text fill=\"#3a3835\" font-family=\"Inter,sans-serif\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"105\" y=\"118\">SessionMiddleware</text>\n<rect fill=\"#f2f0ec\" height=\"36\" rx=\"6\" stroke=\"#d9d5ce\" stroke-width=\"1\" width=\"170\" x=\"20\" y=\"144\"></rect>\n<text fill=\"#3a3835\" font-family=\"Inter,sans-serif\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"105\" y=\"166\">AuthenticationMiddleware</text>\n<rect fill=\"#deeaf7\" height=\"36\" rx=\"6\" stroke=\"#2d5a8e\" stroke-width=\"1\" width=\"170\" x=\"20\" y=\"192\"></rect>\n<text fill=\"#1e3a5f\" font-family=\"Inter,sans-serif\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"105\" y=\"214\">URLconf (urls.py)</text>\n<line marker-end=\"url(#a2)\" stroke=\"#a8a49f\" stroke-width=\"1\" x1=\"105\" x2=\"105\" y1=\"84\" y2=\"96\"></line>\n<line marker-end=\"url(#a2)\" stroke=\"#a8a49f\" stroke-width=\"1\" x1=\"105\" x2=\"105\" y1=\"132\" y2=\"144\"></line>\n<line marker-end=\"url(#a2)\" stroke=\"#a8a49f\" stroke-width=\"1\" x1=\"105\" x2=\"105\" y1=\"180\" y2=\"192\"></line>\n<line marker-end=\"url(#a2)\" stroke=\"#6b6760\" stroke-width=\"1\" x1=\"190\" x2=\"228\" y1=\"210\" y2=\"210\"></line>\n<rect fill=\"#e8f2ec\" height=\"116\" rx=\"8\" stroke=\"#2d6e45\" stroke-width=\"1.5\" width=\"130\" x=\"230\" y=\"152\"></rect>\n<text fill=\"#1a4a2e\" font-family=\"Inter,sans-serif\" font-size=\"13\" font-weight=\"700\" text-anchor=\"middle\" x=\"295\" y=\"182\">View</text>\n<text fill=\"#2d6e45\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"295\" y=\"200\">1. Receive request</text>\n<text fill=\"#2d6e45\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"295\" y=\"216\">2. Query models</text>\n<text fill=\"#2d6e45\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"295\" y=\"232\">3. Render template</text>\n<text fill=\"#2d6e45\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"295\" y=\"248\">4. Return response</text>\n<line marker-end=\"url(#a2)\" stroke=\"#6b6760\" stroke-dasharray=\"4 3\" stroke-width=\"1\" x1=\"295\" x2=\"295\" y1=\"268\" y2=\"298\"></line>\n<rect fill=\"#ede5f7\" height=\"32\" rx=\"6\" stroke=\"#7a3eb0\" stroke-width=\"1\" width=\"134\" x=\"228\" y=\"300\"></rect>\n<text fill=\"#4a1d6e\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"295\" y=\"320\">PostgreSQL</text>\n<line marker-end=\"url(#a2)\" stroke=\"#6b6760\" stroke-width=\"1\" x1=\"360\" x2=\"398\" y1=\"210\" y2=\"210\"></line>\n<rect fill=\"#f5edd8\" height=\"36\" rx=\"6\" stroke=\"#8b5e2a\" stroke-width=\"1\" width=\"140\" x=\"400\" y=\"192\"></rect>\n<text fill=\"#5c3a1a\" font-family=\"Inter,sans-serif\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"470\" y=\"214\">Template Engine</text>\n<line marker-end=\"url(#a2)\" stroke=\"#6b6760\" stroke-width=\"1\" x1=\"470\" x2=\"470\" y1=\"228\" y2=\"260\"></line>\n<rect fill=\"#1a1917\" height=\"36\" rx=\"6\" stroke=\"#3a3835\" stroke-width=\"1\" width=\"140\" x=\"400\" y=\"262\"></rect>\n<text fill=\"#7dd8a0\" font-family=\"Inter,sans-serif\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"470\" y=\"284\">HttpResponse</text>\n<text fill=\"#a8a49f\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-style=\"italic\" text-anchor=\"middle\" x=\"340\" y=\"360\">Middleware wraps every request and response \u2014 it's the onion model</text>\n</svg>\n</div>\n<div class=\"callout\"><div class=\"callout-label\"> Design Philosophy \u2014 The Onion Model</div><p>Middleware in Django follows the <strong>onion model</strong>: each middleware wraps the request on the way in and the response on the way out. This is why you can add authentication, caching, or CSRF protection to your entire application with a single line in <code>MIDDLEWARE</code> \u2014 no changes to individual views needed.</p></div>\n</section>\n<section data-section=\"\" id=\"models\">\n<div class=\"section-header\"><div class=\"section-num\">04</div><div>\n<div class=\"section-title\">Models From Scratch</div>\n<div class=\"section-subtitle\">The philosophical foundation of Django's ORM</div>\n</div></div>\n<div class=\"philosophy-block\">\n A Model is not just a database table. It is your application's understanding of what a <em>thing</em> is \u2014 its attributes, its behaviors, its relationships. The database is merely where that understanding persists.\n <span>On Django's Model Layer</span>\n</div>\n<p>In a vanilla stack, you write raw SQL <code>CREATE TABLE</code> statements and craft manual queries. The database and your code are two separate worlds you must manually keep in sync. Django's ORM collapses those two worlds. A <strong>Model</strong> is a Python class that simultaneously defines a PostgreSQL table schema, a Python object, a query API, and validation rules.</p>\n<div class=\"cards\">\n<div class=\"card\"><div class=\"card-icon tone-success\"></div><h4>Defines a DB Table</h4><p>Each model class maps to exactly one PostgreSQL table. Class attributes become columns. Django auto-generates the <code>CREATE TABLE</code> SQL.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-info\"></div><h4>Defines a Python Object</h4><p>Each row in that table becomes an instance of your class. Call methods on it, traverse related objects, manipulate data as Python.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-tip\"></div><h4>Defines a Query API</h4><p>Through the Manager (<code>Product.objects</code>), you get <code>.filter()</code>, <code>.exclude()</code>, <code>.order_by()</code>, <code>.annotate()</code> \u2014 all generating optimized SQL.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-info\"></div><h4>Defines Validation</h4><p>Field types, <code>max_length</code>, <code>null</code>, <code>blank</code>, <code>choices</code> \u2014 these constraints live in the model and are enforced at both the Python level and the DB level.</p></div>\n</div>\n<h2>Anatomy of a Model</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">store/models.py \u2014 complete example</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.db <span>import</span> models\n<span>from</span> django.utils.text <span>import</span> slugify\n\n\n<span>class</span> <span>Product</span>(models.<span>Model</span>):\n <span>\"\"\"\n Each instance = one row in the 'store_product' table in PostgreSQL.\n Table name defaults to: appname_modelname (lowercase).\n \"\"\"</span>\n\n <span># \u2500\u2500 TEXT FIELDS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n name = models.<span>CharField</span>(max_length=<span>200</span>)\n slug = models.<span>SlugField</span>(unique=<span>True</span>, max_length=<span>220</span>)\n description = models.<span>TextField</span>(blank=<span>True</span>)\n\n <span># \u2500\u2500 NUMERIC FIELDS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n price = models.<span>DecimalField</span>(max_digits=<span>10</span>, decimal_places=<span>2</span>)\n stock = models.<span>PositiveIntegerField</span>(default=<span>0</span>)\n\n <span># \u2500\u2500 BOOLEAN \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n is_active = models.<span>BooleanField</span>(default=<span>True</span>)\n\n <span># \u2500\u2500 TIMESTAMPS (auto-managed) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n created_at = models.<span>DateTimeField</span>(auto_now_add=<span>True</span>) <span># set once on create</span>\n updated_at = models.<span>DateTimeField</span>(auto_now=<span>True</span>) <span># updated on every .save()</span>\n\n <span># \u2500\u2500 META: controls table-level behavior \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n <span>class</span> <span>Meta</span>:\n ordering = [<span>'-created_at'</span>] <span># default ORDER BY</span>\n verbose_name = <span>'Product'</span>\n verbose_name_plural = <span>'Products'</span>\n db_table = <span>'store_products'</span> <span># override default table name</span>\n indexes = [\n models.<span>Index</span>(fields=[<span>'slug'</span>]),\n models.<span>Index</span>(fields=[<span>'-created_at'</span>, <span>'is_active'</span>]),\n ]\n constraints = [\n models.<span>CheckConstraint</span>(\n check=models.<span>Q</span>(price__gt=<span>0</span>),\n name=<span>'price_must_be_positive'</span>,\n )\n ]\n\n <span># \u2500\u2500 STRING REPRESENTATION \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n <span>def</span> <span>__str__</span>(self) -&gt; str:\n <span>return</span> self.name\n\n <span># \u2500\u2500 OVERRIDE SAVE for auto-slug \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n <span>def</span> <span>save</span>(self, *args, **kwargs):\n <span>if not</span> self.slug:\n self.slug = <span>slugify</span>(self.name)\n <span>super</span>().<span>save</span>(*args, **kwargs)\n\n <span># \u2500\u2500 BUSINESS LOGIC (Fat Models pattern) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n <span>def</span> <span>is_in_stock</span>(self) -&gt; bool:\n <span>return</span> self.stock &gt; <span>0</span>\n\n <span>def</span> <span>discounted_price</span>(self, percent: float):\n <span>from</span> decimal <span>import</span> Decimal\n <span>return</span> self.price * Decimal(str(<span>1</span> - percent / <span>100</span>))</code></pre></div>\n<div class=\"callout\"><div class=\"callout-label\"> Fat Models, Thin Views</div><p>Notice <code>is_in_stock()</code> and <code>discounted_price()</code> live on the model itself. This is the <strong>\"Fat Models, Thin Views\"</strong> principle: business logic belongs close to the data it operates on. Views should only orchestrate \u2014 fetch data, render template. Models carry the domain knowledge. This makes code testable, reusable, and maintainable.</p></div>\n<h2>What Django generates in PostgreSQL</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Auto-generated SQL sent to PostgreSQL</span><span class=\"code-lang\">sql</span></div><pre><code><span>CREATE TABLE</span> store_products (\n id <span>BIGSERIAL PRIMARY KEY</span>, <span>-- Always auto-added! Never declare manually.</span>\n name <span>VARCHAR</span>(<span>200</span>) <span>NOT NULL</span>,\n slug <span>VARCHAR</span>(<span>220</span>) <span>NOT NULL UNIQUE</span>,\n description <span>TEXT</span> <span>NOT NULL DEFAULT</span> <span>''</span>,\n price <span>NUMERIC</span>(<span>10</span>, <span>2</span>) <span>NOT NULL</span>,\n stock <span>INTEGER</span> <span>NOT NULL DEFAULT</span> <span>0</span> <span>CHECK</span> (stock &gt;= <span>0</span>),\n is_active <span>BOOLEAN</span> <span>NOT NULL DEFAULT</span> <span>TRUE</span>,\n created_at <span>TIMESTAMPTZ</span> <span>NOT NULL</span>,\n updated_at <span>TIMESTAMPTZ</span> <span>NOT NULL</span>,\n <span>CONSTRAINT</span> price_must_be_positive <span>CHECK</span> (price &gt; <span>0</span>)\n);\n<span>CREATE INDEX</span> store_products_slug_idx <span>ON</span> store_products (slug);\n<span>CREATE INDEX</span> store_products_created_active <span>ON</span> store_products (created_at <span>DESC</span>, is_active);</code></pre></div>\n<div class=\"callout tone-info\"><div class=\"callout-label\"> The automatic id field</div><p>Django automatically adds a <code>BigAutoField</code> (BIGSERIAL) primary key called <code>id</code> to every model. You never declare it. Override with <code>primary_key=True</code> on another field, or set <code>DEFAULT_AUTO_FIELD = 'django.db.models.UUIDField'</code> globally for UUID primary keys \u2014 great for security-sensitive APIs.</p></div>\n</section>\n<section data-section=\"\" id=\"fields\">\n<div class=\"section-header\"><div class=\"section-num\">05</div><div>\n<div class=\"section-title\">Fields Deep Dive</div>\n<div class=\"section-subtitle\">Every field, its PostgreSQL type, and when to use it</div>\n</div></div>\n<p>Django fields are the bridge between Python types and PostgreSQL column types. Choosing the right field matters \u2014 it affects storage efficiency, validation, what query lookups are available, and performance.</p>\n<table>\n<thead><tr><th>Django Field</th><th>PostgreSQL Type</th><th>Notes</th></tr></thead>\n<tbody>\n<tr><td>CharField</td><td>VARCHAR(n)</td><td>Short strings with known max length. Always set <code>max_length</code>.</td></tr>\n<tr><td>TextField</td><td>TEXT</td><td>Unlimited text \u2014 blog posts, descriptions. No max_length needed.</td></tr>\n<tr><td>EmailField</td><td>VARCHAR(254)</td><td>CharField + email format validation. Use for user emails.</td></tr>\n<tr><td>URLField</td><td>VARCHAR(200)</td><td>CharField + URL validation.</td></tr>\n<tr><td>SlugField</td><td>VARCHAR(50)</td><td>URL-safe strings (letters, numbers, hyphens). Great for SEO URLs.</td></tr>\n<tr><td>UUIDField</td><td>UUID</td><td>Use as PK for public APIs \u2014 prevents ID enumeration attacks.</td></tr>\n<tr><td>IntegerField</td><td>INTEGER</td><td>\u22122,147,483,648 to 2,147,483,647.</td></tr>\n<tr><td>BigIntegerField</td><td>BIGINT</td><td>Use for IDs if you expect &gt; 2 billion rows.</td></tr>\n<tr><td>PositiveIntegerField</td><td>INTEGER + CHECK \u2265 0</td><td>For stock, age, ratings where negative makes no sense.</td></tr>\n<tr><td>FloatField</td><td>DOUBLE PRECISION</td><td>Floating point. Never use for money \u2014 precision errors!</td></tr>\n<tr><td>DecimalField</td><td>NUMERIC(p,s)</td><td>Exact decimal. Always use for currency/financial data.</td></tr>\n<tr><td>BooleanField</td><td>BOOLEAN</td><td>True/False. Add <code>null=True</code> for tri-state (True/False/Unknown).</td></tr>\n<tr><td>DateField</td><td>DATE</td><td>Date only. Use for birthdays, deadlines.</td></tr>\n<tr><td>DateTimeField</td><td>TIMESTAMPTZ</td><td>Date + time, timezone-aware. Use <code>auto_now_add</code> for created_at.</td></tr>\n<tr><td>DurationField</td><td>INTERVAL</td><td>Time intervals \u2014 session lengths, event durations.</td></tr>\n<tr><td>FileField</td><td>VARCHAR(100)</td><td>Stores the file path. Actual file goes to storage backend (S3 etc.).</td></tr>\n<tr><td>ImageField</td><td>VARCHAR(100)</td><td>FileField + image validation. Requires Pillow.</td></tr>\n<tr><td>JSONField</td><td>JSONB</td><td>Store JSON data. Fully queryable in PostgreSQL. Powerful \u2014 use wisely.</td></tr>\n<tr><td>ArrayField*</td><td>TYPE[]</td><td>PostgreSQL-specific arrays. Requires <code>django.contrib.postgres</code>.</td></tr>\n<tr><td>HStoreField*</td><td>HSTORE</td><td>Key-value pairs. Often replaced by JSONField today.</td></tr>\n</tbody>\n</table>\n<p>* PostgreSQL-specific fields from <code>django.contrib.postgres.fields</code></p>\n<h2>The null vs blank distinction</h2>\n<div class=\"callout tone-danger\"><div class=\"callout-label\"> Most common Django confusion</div><p><code>null=True</code> affects the <strong>database</strong> \u2014 it allows a NULL value in PostgreSQL. <code>blank=True</code> affects <strong>Python validation</strong> \u2014 it allows empty values in forms. For text fields, never use <code>null=True</code> \u2014 Django convention is to store empty strings, not NULLs. For non-text fields (ForeignKey, DateField, IntegerField), use <code>null=True</code> when the value is genuinely optional.</p></div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Field options reference</span><span class=\"code-lang\">python</span></div><pre><code><span>class</span> <span>Order</span>(models.<span>Model</span>):\n\n <span>class</span> <span>Status</span>(models.<span>TextChoices</span>):\n PENDING = <span>'PE'</span>, <span>'Pending'</span>\n CONFIRMED = <span>'CO'</span>, <span>'Confirmed'</span>\n SHIPPED = <span>'SH'</span>, <span>'Shipped'</span>\n DELIVERED = <span>'DE'</span>, <span>'Delivered'</span>\n CANCELLED = <span>'CA'</span>, <span>'Cancelled'</span>\n\n status = models.<span>CharField</span>(\n max_length=<span>2</span>,\n choices=<span>Status</span>.choices,\n default=<span>Status</span>.PENDING,\n )\n\n <span># Text fields: use blank=True, NOT null=True</span>\n notes = models.<span>TextField</span>(blank=<span>True</span>, default=<span>''</span>)\n\n <span># Optional FK: use null=True + blank=True</span>\n coupon = models.<span>ForeignKey</span>(\n <span>'Coupon'</span>, null=<span>True</span>, blank=<span>True</span>, on_delete=models.<span>SET_NULL</span>\n )\n\n <span># Access enum cleanly:</span>\n <span># order.get_status_display() \u2192 'Confirmed'</span>\n <span># order.status == Order.Status.CONFIRMED \u2192 True</span></code></pre></div>\n</section>\n<section data-section=\"\" id=\"relationships\">\n<div class=\"section-header\"><div class=\"section-num\">06</div><div>\n<div class=\"section-title\">Relationships</div>\n<div class=\"section-subtitle\">How models connect \u2014 and what PostgreSQL builds beneath</div>\n</div></div>\n<p>The real power of a relational database is relationships. Django gives you three high-level relationship fields that map directly to PostgreSQL's foreign key system.</p>\n<h2>ForeignKey \u2014 Many-to-One</h2>\n<p>The most common relationship. Many orders belong to one user. Many articles belong to one author.</p>\n<div>\n<div>\n<div>auth_user</div>\n<div class=\"field\"><span class=\"fname\">id</span><span class=\"ftype\">BIGSERIAL</span><span>PK</span></div>\n<div class=\"field\"><span class=\"fname\">username</span><span class=\"ftype\">VARCHAR</span></div>\n<div class=\"field\"><span class=\"fname\">email</span><span class=\"ftype\">VARCHAR</span></div>\n</div>\n<div>\n<div>1 : N</div>\n\n<div>ForeignKey</div>\n</div>\n<div>\n<div>store_order</div>\n<div class=\"field\"><span class=\"fname\">id</span><span class=\"ftype\">BIGSERIAL</span><span>PK</span></div>\n<div class=\"field\"><span class=\"fname\">user_id</span><span class=\"ftype\">BIGINT</span><span>FK \u2192 user.id</span></div>\n<div class=\"field\"><span class=\"fname\">total</span><span class=\"ftype\">NUMERIC</span></div>\n<div class=\"field\"><span class=\"fname\">status</span><span class=\"ftype\">VARCHAR(2)</span></div>\n</div>\n</div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">ForeignKey \u2014 full example</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.contrib.auth <span>import</span> get_user_model\n\n<span>User</span> = get_user_model() <span># always use this, not import User directly</span>\n\n<span>class</span> <span>Order</span>(models.<span>Model</span>):\n user = models.<span>ForeignKey</span>(\n <span>User</span>,\n on_delete=models.<span>CASCADE</span>, <span># delete orders when user is deleted</span>\n related_name=<span>'orders'</span>, <span># user.orders.all() \u2192 reverse access</span>\n )\n total = models.<span>DecimalField</span>(max_digits=<span>10</span>, decimal_places=<span>2</span>)\n\n<span># \u2500\u2500 Forward access (Order \u2192 User)</span>\norder = <span>Order</span>.objects.<span>get</span>(id=<span>1</span>)\nprint(order.user.username) <span># \u2192 'alice' (hits DB to fetch user)</span>\nprint(order.user_id) <span># \u2192 42 (raw FK int \u2014 no DB hit!)</span>\n\n<span># \u2500\u2500 Reverse access (User \u2192 Orders)</span>\nuser = <span>User</span>.objects.<span>get</span>(username=<span>'alice'</span>)\nuser.orders.<span>all</span>()\nuser.orders.<span>filter</span>(status=<span>'SH'</span>).<span>order_by</span>(<span>'-created_at'</span>)</code></pre></div>\n<table>\n<tr><th>on_delete option</th><th>What happens when parent is deleted</th><th>Use when</th></tr>\n<tr><td><code>CASCADE</code></td><td>Delete all child objects too</td><td>Children have no meaning without the parent (order \u2192 items)</td></tr>\n<tr><td><code>PROTECT</code></td><td>Raises ProtectedError \u2014 prevents deletion</td><td>Enforce integrity (can't delete a category that has products)</td></tr>\n<tr><td><code>SET_NULL</code></td><td>Sets FK to NULL (requires <code>null=True</code>)</td><td>Parent is optional (delete an author, keep their posts as unattributed)</td></tr>\n<tr><td><code>SET_DEFAULT</code></td><td>Sets FK to field's default value</td><td>You have a \"fallback\" relationship</td></tr>\n<tr><td><code>DO_NOTHING</code></td><td>Does nothing \u2014 you handle it</td><td>Advanced use only. Can leave orphaned rows.</td></tr>\n</table>\n<h2>ManyToManyField</h2>\n<p>A product can belong to many categories. A category can contain many products. Django automatically creates a <strong>junction table</strong> in PostgreSQL.</p>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">ManyToMany example</span><span class=\"code-lang\">python</span></div><pre><code><span>class</span> <span>Category</span>(models.<span>Model</span>):\n name = models.<span>CharField</span>(max_length=<span>100</span>)\n\n<span>class</span> <span>Product</span>(models.<span>Model</span>):\n name = models.<span>CharField</span>(max_length=<span>200</span>)\n categories = models.<span>ManyToManyField</span>(<span>Category</span>, related_name=<span>'products'</span>, blank=<span>True</span>)\n\n<span># Django auto-creates this junction table in PostgreSQL:</span>\n<span># CREATE TABLE store_product_categories (</span>\n<span># id BIGSERIAL PRIMARY KEY,</span>\n<span># product_id BIGINT REFERENCES store_product(id) ON DELETE CASCADE,</span>\n<span># category_id BIGINT REFERENCES store_category(id) ON DELETE CASCADE,</span>\n<span># UNIQUE(product_id, category_id)</span>\n<span># );</span>\n\n<span># \u2500\u2500 Managing the relationship</span>\nproduct.categories.<span>add</span>(electronics)\nproduct.categories.<span>set</span>([electronics, phones]) <span># replace all</span>\nproduct.categories.<span>remove</span>(phones)\nproduct.categories.<span>clear</span>()\n\n<span># \u2500\u2500 Querying through the relationship</span>\nCategory.objects.<span>get</span>(name=<span>'Electronics'</span>).products.<span>all</span>()</code></pre></div>\n<h2>OneToOneField</h2>\n<p>Like ForeignKey but enforces uniqueness \u2014 exactly one related object. Classic use: extending Django's User model.</p>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">OneToOne \u2014 extending User</span><span class=\"code-lang\">python</span></div><pre><code><span>class</span> <span>UserProfile</span>(models.<span>Model</span>):\n user = models.<span>OneToOneField</span>(<span>User</span>, on_delete=models.<span>CASCADE</span>, related_name=<span>'profile'</span>)\n bio = models.<span>TextField</span>(blank=<span>True</span>)\n avatar = models.<span>ImageField</span>(upload_to=<span>'avatars/'</span>, blank=<span>True</span>)\n\n<span># Bidirectional single-object access</span>\nuser.profile.bio <span># forward</span>\nprofile.user.username <span># backward</span></code></pre></div>\n</section>\n<section data-section=\"\" id=\"migrations\">\n<div class=\"section-header\"><div class=\"section-num\">07</div><div>\n<div class=\"section-title\">Migrations</div>\n<div class=\"section-subtitle\">Version control for your database schema</div>\n</div></div>\n<div class=\"philosophy-block\">\n A migration is not just a database change. It is a record of your application's evolving understanding of its data. Every migration is a commit in your schema's git history.\n <span>On Database Migrations</span>\n</div>\n<p>When you change a model \u2014 add a field, rename a table, create an index \u2014 Django doesn't automatically update the database. Instead, you generate a <strong>migration file</strong>: a Python file that describes exactly what changed and how to apply (and reverse) it. You then apply that file to update PostgreSQL.</p>\n<div>\n<div class=\"step\"><div class=\"step-num\">1</div><div class=\"step-content\"><h4>Edit your model</h4><p>Make changes to <code>models.py</code> \u2014 add a field, change a type, add a relationship, add an index.</p></div></div>\n<div class=\"step\"><div class=\"step-num\">2</div><div class=\"step-content\"><h4>Generate the migration</h4><p><code>python manage.py makemigrations</code> \u2014 Django diffs the current models against the last migration and generates a new file describing what changed.</p></div></div>\n<div class=\"step\"><div class=\"step-num\">3</div><div class=\"step-content\"><h4>Review the file</h4><p>Open the generated file in <code>migrations/</code>. Read it. Understand it. This SQL will run against your production database.</p></div></div>\n<div class=\"step\"><div class=\"step-num\">4</div><div class=\"step-content\"><h4>Apply it</h4><p><code>python manage.py migrate</code> \u2014 Django runs the migration SQL against PostgreSQL and records it in the <code>django_migrations</code> table as applied.</p></div></div>\n</div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Generated migration file</span><span class=\"code-lang\">python</span></div><pre><code><span># store/migrations/0003_product_add_weight.py</span>\n<span>from</span> django.db <span>import</span> migrations, models\n\n<span>class</span> <span>Migration</span>(migrations.<span>Migration</span>):\n\n dependencies = [(<span>'store'</span>, <span>'0002_order'</span>)] <span># must run AFTER this</span>\n\n operations = [\n migrations.<span>AddField</span>(\n model_name=<span>'product'</span>,\n name=<span>'weight_grams'</span>,\n field=models.<span>PositiveIntegerField</span>(default=<span>0</span>, help_text=<span>'Weight in grams'</span>),\n ),\n migrations.<span>AddIndex</span>(\n model_name=<span>'product'</span>,\n index=models.<span>Index</span>(fields=[<span>'weight_grams'</span>], name=<span>'product_weight_idx'</span>),\n ),\n ]</code></pre></div>\n<h2>Migration history \u2014 a timeline</h2>\n<div>\n<div class=\"migration-item\"><div class=\"mi-file\">0001_initial.py</div><div class=\"mi-desc\">Creates the Product table with all base fields</div></div>\n<div class=\"migration-item\"><div class=\"mi-file\">0002_order.py</div><div class=\"mi-desc\">Creates the Order table + ForeignKey to User</div></div>\n<div class=\"migration-item\"><div class=\"mi-file\">0003_product_add_weight.py</div><div class=\"mi-desc\">Adds weight_grams column + index to Product</div></div>\n<div class=\"migration-item\"><div class=\"mi-file\">0004_alter_product_slug.py</div><div class=\"mi-desc\">Changes slug max_length from 50 to 220</div></div>\n<div class=\"migration-item\"><div class=\"mi-file\">0005_userprofile.py</div><div class=\"mi-desc\">Creates UserProfile with OneToOneField to User</div></div>\n</div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Essential migration commands</span><span class=\"code-lang\">bash</span></div><pre><code><span># Create migrations for all changed apps</span>\npython manage.py makemigrations\n\n<span># For a specific app only</span>\npython manage.py makemigrations store\n\n<span># Apply all pending migrations</span>\npython manage.py migrate\n\n<span># Roll back to a specific migration (pass the number BEFORE the one you want to undo)</span>\npython manage.py migrate store 0002\n\n<span># See migration status across all apps</span>\npython manage.py showmigrations\n\n<span># Preview the SQL before applying (essential for production)</span>\npython manage.py sqlmigrate store 0003\n\n<span># Check for model inconsistencies</span>\npython manage.py check</code></pre></div>\n<div class=\"callout tone-danger\"><div class=\"callout-label\"> Production migration rules</div><p><strong>Always commit migrations alongside model changes.</strong> Never delete or edit an already-applied migration. Use <code>sqlmigrate</code> to review SQL before running on production. For large tables: adding a NOT NULL column without a default locks the table \u2014 add with <code>null=True</code> first, backfill data in a data migration, then add the constraint in a third migration. Use Django's <code>RunPython</code> for data migrations.</p></div>\n</section>\n<section data-section=\"\" id=\"postgres\">\n<div class=\"section-header\"><div class=\"section-num\">08</div><div>\n<div class=\"section-title\">PostgreSQL Internals</div>\n<div class=\"section-subtitle\">What PostgreSQL is, how it works, and why it's the right choice</div>\n</div></div>\n<div class=\"philosophy-block\">\n PostgreSQL is not \"a database\". It is a 35-year-old, ACID-compliant, standards-conforming, production-proven system that happens to speak SQL. It is the substrate on which trust is built.\n <span>On Choosing Your Database</span>\n</div>\n<div>\n<svg viewbox=\"0 0 680 320\" xmlns=\"http://www.w3.org/2000/svg\">\n<defs><marker id=\"a3\" markerheight=\"6\" markerwidth=\"6\" orient=\"auto-start-reverse\" refx=\"8\" refy=\"5\" viewbox=\"0 0 10 10\"><path d=\"M2 1L8 5L2 9\" fill=\"none\" stroke=\"#6b6760\" stroke-linecap=\"round\" stroke-linejoin=\"round\" stroke-width=\"1.5\"></path></marker></defs>\n<rect fill=\"#e8f2ec\" height=\"48\" rx=\"8\" stroke=\"#2d6e45\" stroke-width=\"1\" width=\"100\" x=\"10\" y=\"116\"></rect>\n<text fill=\"#1a4a2e\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"60\" y=\"137\">Django App</text>\n<text fill=\"#2d6e45\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"60\" y=\"153\">psycopg2</text>\n<line marker-end=\"url(#a3)\" stroke=\"#6b6760\" stroke-width=\"1\" x1=\"110\" x2=\"148\" y1=\"140\" y2=\"140\"></line>\n<rect fill=\"#f2f0ec\" height=\"224\" rx=\"12\" stroke=\"#d9d5ce\" stroke-width=\"1\" width=\"510\" x=\"150\" y=\"48\"></rect>\n<text fill=\"#3a3835\" font-family=\"Inter,sans-serif\" font-size=\"12\" font-weight=\"600\" text-anchor=\"middle\" x=\"405\" y=\"78\">PostgreSQL Server (postmaster process)</text>\n<rect fill=\"#deeaf7\" height=\"42\" rx=\"6\" stroke=\"#2d5a8e\" stroke-width=\"1\" width=\"148\" x=\"170\" y=\"94\"></rect>\n<text fill=\"#1e3a5f\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"244\" y=\"111\">Connection Pool</text>\n<text fill=\"#2d5a8e\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"244\" y=\"127\">backend process / conn</text>\n<line marker-end=\"url(#a3)\" stroke=\"#a8a49f\" stroke-width=\"1\" x1=\"318\" x2=\"352\" y1=\"115\" y2=\"115\"></line>\n<rect fill=\"#ede5f7\" height=\"42\" rx=\"6\" stroke=\"#7a3eb0\" stroke-width=\"1\" width=\"170\" x=\"354\" y=\"94\"></rect>\n<text fill=\"#4a1d6e\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"439\" y=\"111\">Query Planner / Executor</text>\n<text fill=\"#6a3d9e\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"439\" y=\"127\">parse \u2192 plan \u2192 execute</text>\n<rect fill=\"#f5edd8\" height=\"48\" rx=\"6\" stroke=\"#8b5e2a\" stroke-width=\"1\" width=\"155\" x=\"170\" y=\"158\"></rect>\n<text fill=\"#5c3a1a\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"247\" y=\"178\">Shared Buffer Cache</text>\n<text fill=\"#8b5e2a\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"247\" y=\"194\">hot pages in RAM \u2014 fast</text>\n<rect fill=\"#fdeaea\" height=\"48\" rx=\"6\" stroke=\"#7a1f1f\" stroke-width=\"1\" width=\"160\" x=\"374\" y=\"158\"></rect>\n<text fill=\"#5a1818\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"454\" y=\"178\">WAL (Write-Ahead Log)</text>\n<text fill=\"#7a1f1f\" font-family=\"Inter,sans-serif\" font-size=\"10\" text-anchor=\"middle\" x=\"454\" y=\"194\">crash recovery + replication</text>\n<rect fill=\"#1a1917\" height=\"34\" rx=\"6\" stroke=\"#3a3835\" stroke-width=\"1\" width=\"364\" x=\"170\" y=\"226\"></rect>\n<text fill=\"#7dd8a0\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-weight=\"600\" text-anchor=\"middle\" x=\"352\" y=\"247\">Data Files on Disk (PGDATA) \u2014 Tables, Indexes, Sequences</text>\n<line marker-end=\"url(#a3)\" stroke=\"#a8a49f\" stroke-dasharray=\"3 2\" stroke-width=\"1\" x1=\"244\" x2=\"244\" y1=\"136\" y2=\"158\"></line>\n<line marker-end=\"url(#a3)\" stroke=\"#a8a49f\" stroke-dasharray=\"3 2\" stroke-width=\"1\" x1=\"439\" x2=\"454\" y1=\"136\" y2=\"158\"></line>\n<line marker-end=\"url(#a3)\" stroke=\"#a8a49f\" stroke-dasharray=\"3 2\" stroke-width=\"1\" x1=\"247\" x2=\"280\" y1=\"206\" y2=\"226\"></line>\n<line marker-end=\"url(#a3)\" stroke=\"#a8a49f\" stroke-dasharray=\"3 2\" stroke-width=\"1\" x1=\"454\" x2=\"420\" y1=\"206\" y2=\"226\"></line>\n<text fill=\"#a8a49f\" font-family=\"Inter,sans-serif\" font-size=\"11\" font-style=\"italic\" text-anchor=\"middle\" x=\"405\" y=\"302\">Django connects via psycopg2 \u2014 PostgreSQL handles concurrency, durability, and planning</text>\n</svg>\n</div>\n<h2>Why PostgreSQL and not SQLite or MySQL?</h2>\n<table>\n<tr><th>Feature</th><th>PostgreSQL</th><th>SQLite</th><th>MySQL / MariaDB</th></tr>\n<tr><td>ACID transactions</td><td><span class=\"tone-success\">Full MVCC</span></td><td><span>Partial</span></td><td><span>Partial</span></td></tr>\n<tr><td>JSON support</td><td><span class=\"tone-success\">JSONB \u2014 indexed!</span></td><td><span class=\"tone-danger\">Text only</span></td><td><span>Basic JSON</span></td></tr>\n<tr><td>Array columns</td><td><span class=\"tone-success\">Native</span></td><td><span class=\"tone-danger\">No</span></td><td><span class=\"tone-danger\">No</span></td></tr>\n<tr><td>Full-text search</td><td><span class=\"tone-success\">tsvector \u2014 built-in</span></td><td><span class=\"tone-danger\">No</span></td><td><span>Basic</span></td></tr>\n<tr><td>Window functions</td><td><span class=\"tone-success\">Full</span></td><td><span>Limited</span></td><td><span>Limited</span></td></tr>\n<tr><td>Concurrent writes</td><td><span class=\"tone-success\">MVCC \u2014 readers don't block writers</span></td><td><span class=\"tone-danger\">Table locks</span></td><td><span>Good</span></td></tr>\n<tr><td>Django support tier</td><td><span class=\"tone-success\">Tier 1 + postgres extras</span></td><td><span>Dev / testing only</span></td><td><span>Tier 2</span></td></tr>\n<tr><td>Partial indexes</td><td><span class=\"tone-success\">Yes</span></td><td><span class=\"tone-danger\">No</span></td><td><span class=\"tone-danger\">No</span></td></tr>\n</table>\n<h2>ACID \u2014 the four guarantees PostgreSQL keeps for you</h2>\n<div class=\"cards\">\n<div class=\"card\"><div class=\"card-icon tone-success\"></div><h4>Atomicity</h4><p>A transaction either completes entirely or not at all. Update stock AND create an order in one transaction \u2014 either both happen or neither happens. No partial states.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-info\"></div><h4>Consistency</h4><p>The database always goes from one valid state to another. Constraints (NOT NULL, UNIQUE, FK, CHECK) are enforced. An invalid transaction is rejected, leaving the DB unchanged.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-tip\"></div><h4>Isolation</h4><p>Concurrent transactions don't see each other's in-progress changes. PostgreSQL uses MVCC (Multi-Version Concurrency Control) \u2014 readers never block writers.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-info\"></div><h4>Durability</h4><p>Once committed, data is permanently saved \u2014 even if the server crashes immediately after. PostgreSQL's Write-Ahead Log (WAL) ensures every commit is on disk first.</p></div>\n</div>\n</section>\n<section data-section=\"\" id=\"postgres-django\">\n<div class=\"section-header\"><div class=\"section-num\">09</div><div>\n<div class=\"section-title\">PostgreSQL + Django</div>\n<div class=\"section-subtitle\">Django's postgres-specific extras that go beyond the generic ORM</div>\n</div></div>\n<p>When you use PostgreSQL with Django, you unlock a second tier of capabilities via <code>django.contrib.postgres</code>. These features only exist because PostgreSQL supports them natively \u2014 you cannot use them with SQLite or MySQL.</p>\n<div class=\"callout tone-info\"><div class=\"callout-label\"> Enable django.contrib.postgres</div><p>Add <code>'django.contrib.postgres'</code> to <code>INSTALLED_APPS</code>. This adds no database tables \u2014 it simply unlocks the Python-level API for PostgreSQL-specific fields, lookups, and aggregations.</p></div>\n<h2>ArrayField \u2014 real arrays in your columns</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">ArrayField example</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.contrib.postgres.fields <span>import</span> ArrayField\n\n<span>class</span> <span>Product</span>(models.<span>Model</span>):\n name = models.<span>CharField</span>(max_length=<span>200</span>)\n tags = <span>ArrayField</span>(\n models.<span>CharField</span>(max_length=<span>50</span>),\n blank=<span>True</span>, default=list,\n )\n <span># \u2192 PostgreSQL: tags VARCHAR(50)[] NOT NULL DEFAULT '{}'</span>\n\n<span># Querying arrays</span>\n<span>Product</span>.objects.<span>filter</span>(tags__contains=[<span>'sale'</span>]) <span># has 'sale' tag</span>\n<span>Product</span>.objects.<span>filter</span>(tags__contained_by=[<span>'a'</span>, <span>'b'</span>]) <span># subset of list</span>\n<span>Product</span>.objects.<span>filter</span>(tags__overlap=[<span>'sale'</span>, <span>'new'</span>]) <span># any of these</span>\n<span>Product</span>.objects.<span>filter</span>(tags__len=<span>3</span>) <span># exactly 3 tags</span></code></pre></div>\n<h2>JSONField \u2014 structured documents inside rows</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">JSONField \u2014 query deep into JSON</span><span class=\"code-lang\">python</span></div><pre><code><span>class</span> <span>Product</span>(models.<span>Model</span>):\n metadata = models.<span>JSONField</span>(default=dict, blank=<span>True</span>)\n <span># \u2192 PostgreSQL: metadata JSONB NOT NULL DEFAULT '{}'</span>\n\n<span># Save nested data</span>\nproduct.metadata = {\n <span>'color'</span>: <span>'red'</span>,\n <span>'dimensions'</span>: {<span>'w'</span>: <span>10</span>, <span>'h'</span>: <span>20</span>},\n <span>'certifications'</span>: [<span>'CE'</span>, <span>'RoHS'</span>],\n}\nproduct.<span>save</span>()\n\n<span># Query deep into JSON (PostgreSQL evaluates this, not Python!)</span>\n<span>Product</span>.objects.<span>filter</span>(metadata__color=<span>'red'</span>)\n<span>Product</span>.objects.<span>filter</span>(metadata__dimensions__w__gte=<span>5</span>)\n<span>Product</span>.objects.<span>filter</span>(metadata__has_key=<span>'color'</span>)\n<span>Product</span>.objects.<span>filter</span>(metadata__has_any_keys=[<span>'color'</span>, <span>'size'</span>])</code></pre></div>\n<h2>Full-text search \u2014 built right into PostgreSQL</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Full-text search</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.contrib.postgres.search <span>import</span> SearchVector, SearchQuery, SearchRank\n\n<span># Weight: A = highest relevance, D = lowest</span>\nvector = <span>SearchVector</span>(<span>'name'</span>, weight=<span>'A'</span>) + <span>SearchVector</span>(<span>'description'</span>, weight=<span>'B'</span>)\nquery = <span>SearchQuery</span>(<span>'wireless headphones'</span>)\n\nresults = <span>Product</span>.objects \\\n .<span>annotate</span>(rank=<span>SearchRank</span>(vector, query)) \\\n .<span>filter</span>(rank__gte=<span>0.1</span>) \\\n .<span>order_by</span>(<span>'-rank'</span>)\n\n<span># Production: store a pre-computed SearchVectorField for speed</span>\n<span>from</span> django.contrib.postgres.search <span>import</span> SearchVectorField\n<span>from</span> django.contrib.postgres.indexes <span>import</span> GinIndex\n\n<span>class</span> <span>Product</span>(models.<span>Model</span>):\n search_vector = <span>SearchVectorField</span>(null=<span>True</span>, editable=<span>False</span>)\n <span>class</span> <span>Meta</span>:\n indexes = [<span>GinIndex</span>(fields=[<span>'search_vector'</span>])]</code></pre></div>\n</section>\n<section data-section=\"\" id=\"queries\">\n<div class=\"section-header\"><div class=\"section-num\">10</div><div>\n<div class=\"section-title\">QuerySet Mastery</div>\n<div class=\"section-subtitle\">Django's lazy, chainable, composable query API</div>\n</div></div>\n<div class=\"philosophy-block\">\n A QuerySet is not a list. It is a promise \u2014 a description of data you intend to retrieve. It only hits the database when you actually need the data. This laziness is a feature, not a quirk.\n <span>On Django QuerySets</span>\n</div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Lazy evaluation \u2014 when the DB is actually hit</span><span class=\"code-lang\">python</span></div><pre><code><span># These do NOT hit the database \u2014 just build the query description</span>\nproducts = <span>Product</span>.objects.<span>filter</span>(is_active=<span>True</span>)\nproducts = products.<span>filter</span>(price__lt=<span>100</span>)\nproducts = products.<span>order_by</span>(<span>'-created_at'</span>)\n\n<span># These DO evaluate \u2014 they hit the database</span>\n<span>for</span> p <span>in</span> products: <span># iteration</span>\n print(p.name)\nlist(products) <span># explicit conversion</span>\nproducts[<span>0</span>] <span># index access</span>\nproducts[<span>0</span>:<span>10</span>] <span># slicing \u2192 LIMIT 10 OFFSET 0</span>\nproducts.<span>count</span>() <span># SELECT COUNT(*) \u2014 efficient, no rows fetched</span>\nproducts.<span>exists</span>() <span># SELECT 1 WHERE... LIMIT 1 \u2014 fastest existence check</span>\nproducts.<span>first</span>() / .<span>last</span>() <span># LIMIT 1 with ordering</span></code></pre></div>\n<h2>Filter lookups \u2014 SQL operators as Python keywords</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">All lookup types</span><span class=\"code-lang\">python</span></div><pre><code><span># \u2500\u2500 EXACT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>Product</span>.objects.<span>filter</span>(name=<span>'iPhone 15'</span>) <span># = 'iPhone 15'</span>\n<span>Product</span>.objects.<span>filter</span>(name__iexact=<span>'iphone 15'</span>) <span># case-insensitive</span>\n\n<span># \u2500\u2500 COMPARISONS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>Product</span>.objects.<span>filter</span>(price__lt=<span>50</span>) <span># price &lt; 50</span>\n<span>Product</span>.objects.<span>filter</span>(price__lte=<span>50</span>) <span># price &lt;= 50</span>\n<span>Product</span>.objects.<span>filter</span>(price__range=(<span>10</span>, <span>50</span>)) <span># BETWEEN 10 AND 50</span>\n\n<span># \u2500\u2500 STRING MATCHING \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>Product</span>.objects.<span>filter</span>(name__contains=<span>'phone'</span>) <span># LIKE '%phone%'</span>\n<span>Product</span>.objects.<span>filter</span>(name__icontains=<span>'phone'</span>) <span># ILIKE '%phone%'</span>\n<span>Product</span>.objects.<span>filter</span>(name__startswith=<span>'i'</span>) <span># LIKE 'i%'</span>\n<span>Product</span>.objects.<span>filter</span>(slug__regex=<span>r'^[a-z]'</span>) <span># POSIX regex</span>\n\n<span># \u2500\u2500 SETS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>Product</span>.objects.<span>filter</span>(status__in=[<span>'active'</span>, <span>'featured'</span>])\n<span>Product</span>.objects.<span>exclude</span>(id__in=[<span>1</span>, <span>2</span>, <span>3</span>]) <span># NOT IN</span>\n\n<span># \u2500\u2500 NULL CHECKS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>Product</span>.objects.<span>filter</span>(coupon__isnull=<span>True</span>)\n\n<span># \u2500\u2500 DATES \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>from</span> django.utils <span>import</span> timezone\n<span>from</span> datetime <span>import</span> timedelta\n\n<span>Product</span>.objects.<span>filter</span>(created_at__year=<span>2024</span>)\n<span>Product</span>.objects.<span>filter</span>(created_at__gte=timezone.<span>now</span>() - timedelta(days=<span>7</span>))\n\n<span># \u2500\u2500 RELATIONSHIP TRAVERSAL (double underscore) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span># Products whose orders were placed by user 'alice'</span>\n<span>Product</span>.objects.<span>filter</span>(order__user__username=<span>'alice'</span>)\n\n<span># \u2500\u2500 Q OBJECTS \u2014 complex AND/OR/NOT logic \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>from</span> django.db.models <span>import</span> Q\n\n<span>Product</span>.objects.<span>filter</span>(\n Q(price__lt=<span>50</span>) | Q(is_featured=<span>True</span>), <span># OR</span>\n is_active=<span>True</span>, <span># AND</span>\n ~Q(name__startswith=<span>'Test'</span>), <span># NOT</span>\n)</code></pre></div>\n<h2>QuerySet vs SQL \u2014 side by side</h2>\n<div>\n<div>\n<div>SQL</div>\n<span>SELECT</span> p.id, p.name, p.price, <span>COUNT</span>(oi.id) <span>AS</span> order_count<br/>\n<span>FROM</span> store_products p<br/>\n<span>LEFT JOIN</span> store_orderitem oi <span>ON</span> oi.product_id = p.id<br/>\n<span>WHERE</span> p.is_active = <span>TRUE AND</span> p.price &lt; <span>100</span><br/>\n<span>GROUP BY</span> p.id <span>HAVING COUNT</span>(oi.id) &gt; <span>5</span><br/>\n<span>ORDER BY</span> order_count <span>DESC LIMIT</span> <span>10</span>;\n </div>\n<div>\n<div>Django ORM equivalent</div>\n<div class=\"code-block\"><pre><code><span>from</span> django.db.models <span>import</span> Count\n\n<span>Product</span>.objects \\\n .<span>filter</span>(is_active=<span>True</span>, price__lt=<span>100</span>) \\\n .<span>annotate</span>(order_count=<span>Count</span>(<span>'orderitem'</span>)) \\\n .<span>filter</span>(order_count__gt=<span>5</span>) \\\n .<span>order_by</span>(<span>'-order_count'</span>) \\\n .<span>values</span>(<span>'id'</span>, <span>'name'</span>, <span>'price'</span>, <span>'order_count'</span>) \\\n [:<span>10</span>]</code></pre></div>\n</div>\n</div>\n<h2>Aggregation and Annotation</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">aggregate vs annotate</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.db.models <span>import</span> Avg, Count, Max, Min, Sum, F\n<span>from</span> django.db.models.functions <span>import</span> TruncDate\n\n<span># \u2500\u2500 AGGREGATE: returns a single dict \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\nstats = <span>Product</span>.objects.<span>filter</span>(is_active=<span>True</span>).<span>aggregate</span>(\n avg_price = <span>Avg</span>(<span>'price'</span>),\n total_stock = <span>Sum</span>(<span>'stock'</span>),\n max_price = <span>Max</span>(<span>'price'</span>),\n count = <span>Count</span>(<span>'id'</span>),\n)\n<span># \u2192 {'avg_price': Decimal('49.99'), 'total_stock': 3420, ...}</span>\n\n<span># \u2500\u2500 ANNOTATE: adds a computed column to EACH row \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\nproducts = <span>Product</span>.objects.<span>annotate</span>(\n order_count = <span>Count</span>(<span>'orderitem'</span>),\n discounted_price = <span>F</span>(<span>'price'</span>) * <span>0.9</span>, <span># F() = reference a DB column</span>\n)\n<span># Each product now has .order_count and .discounted_price \u2014 computed in SQL</span>\n\n<span># \u2500\u2500 GROUP BY \u2014 orders per day \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\ndaily = <span>Order</span>.objects \\\n .<span>annotate</span>(date=<span>TruncDate</span>(<span>'created_at'</span>)) \\\n .<span>values</span>(<span>'date'</span>) \\\n .<span>annotate</span>(count=<span>Count</span>(<span>'id'</span>), revenue=<span>Sum</span>(<span>'total'</span>)) \\\n .<span>order_by</span>(<span>'date'</span>)</code></pre></div>\n</section>\n<section data-section=\"\" id=\"advanced\">\n<div class=\"section-header\"><div class=\"section-num\">11</div><div>\n<div class=\"section-title\">Advanced Patterns</div>\n<div class=\"section-subtitle\">N+1, transactions, select_related, raw SQL, and signals</div>\n</div></div>\n<h2>The N+1 problem \u2014 the most common Django performance bug</h2>\n<div class=\"callout tone-danger\"><div class=\"callout-label\"> The Silent Killer</div><p>You loop over 100 orders and access <code>order.user.username</code> for each one. Django fires 1 query to get the orders, then 100 more queries to get each user. That's 101 queries. On a page showing 1000 orders, that's 1001 queries. The page crawls. This is the N+1 problem \u2014 and it's invisible unless you're watching your query count.</p></div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">N+1 diagnosis and solutions</span><span class=\"code-lang\">python</span></div><pre><code><span># N+1 \u2014 fires 1 + N queries</span>\norders = <span>Order</span>.objects.<span>all</span>()\n<span>for</span> order <span>in</span> orders:\n print(order.user.username) <span># \u2190 DB hit every single iteration</span>\n\n<span># select_related \u2014 for ForeignKey / OneToOne (SQL JOIN)</span>\n<span># \u2192 ONE query with a JOIN. user is already in memory.</span>\norders = <span>Order</span>.objects.<span>select_related</span>(<span>'user'</span>).<span>all</span>()\n\n<span># Deep select_related (traverse multiple FK hops)</span>\norders = <span>Order</span>.objects.<span>select_related</span>(<span>'user__profile'</span>)\n\n<span># prefetch_related \u2014 for ManyToMany / reverse FK</span>\n<span># \u2192 TWO queries: one for products, one for ALL their categories.</span>\n<span># Django stitches them in Python. Much faster than N queries.</span>\nproducts = <span>Product</span>.objects.<span>prefetch_related</span>(<span>'categories'</span>)\n\n<span># Combining both</span>\norders = <span>Order</span>.objects \\\n .<span>select_related</span>(<span>'user'</span>) \\\n .<span>prefetch_related</span>(<span>'items__product__categories'</span>)\n\n<span># only() \u2014 load only specific columns</span>\n<span>Product</span>.objects.<span>only</span>(<span>'id'</span>, <span>'name'</span>, <span>'price'</span>)\n\n<span># defer() \u2014 load everything EXCEPT heavy columns</span>\n<span>Product</span>.objects.<span>defer</span>(<span>'description'</span>)\n\n<span># values() \u2014 dicts instead of objects (fastest read-only)</span>\n<span>Product</span>.objects.<span>values</span>(<span>'id'</span>, <span>'name'</span>, <span>'price'</span>)\n\n<span># values_list() \u2014 tuples or flat list</span>\nids = <span>Product</span>.objects.<span>values_list</span>(<span>'id'</span>, flat=<span>True</span>)</code></pre></div>\n<h2>Atomic transactions</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">django.db.transaction</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.db <span>import</span> transaction\n\n<span># Method 1: @atomic decorator \u2014 wraps the entire function</span>\n<span>@transaction.atomic</span>\n<span>def</span> <span>place_order</span>(user, cart_items):\n order = <span>Order</span>.objects.<span>create</span>(user=user)\n\n <span>for</span> item <span>in</span> cart_items:\n <span># Atomic stock decrement \u2014 race-condition safe</span>\n updated = <span>Product</span>.objects \\\n .<span>filter</span>(id=item.product_id, stock__gte=item.quantity) \\\n .<span>update</span>(stock=<span>F</span>(<span>'stock'</span>) - item.quantity)\n\n <span>if not</span> updated:\n <span>raise</span> <span>ValueError</span>(<span>f\"Insufficient stock\"</span>)\n <span># \u2191 Exception rolls back the ENTIRE transaction</span>\n\n <span>OrderItem</span>.objects.<span>create</span>(order=order, product_id=item.product_id, quantity=item.quantity)\n\n <span>return</span> order\n\n<span># Method 2: context manager</span>\n<span>with</span> transaction.<span>atomic</span>():\n user.balance -= amount\n user.<span>save</span>()\n <span>Payment</span>.objects.<span>create</span>(user=user, amount=amount)\n\n<span># Method 3: savepoints (nested \u2014 for optional sub-operations)</span>\n<span>with</span> transaction.<span>atomic</span>():\n order = <span>Order</span>.objects.<span>create</span>(user=user)\n <span>try</span>:\n <span>with</span> transaction.<span>atomic</span>(): <span># creates a SAVEPOINT</span>\n <span>send_confirmation_email</span>(user)\n <span>except</span> <span>Exception</span>:\n <span>pass</span> <span># email failed \u2014 rolled back to savepoint, order still committed</span></code></pre></div>\n<h2>Raw SQL \u2014 when the ORM isn't enough</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Raw SQL safely</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.db <span>import</span> connection\n\n<span># raw() \u2014 returns model instances (for complex joins, CTEs)</span>\nproducts = <span>Product</span>.objects.<span>raw</span>(\n <span>\"\"\"\n SELECT p.*, COUNT(oi.id) AS order_count\n FROM store_products p\n LEFT JOIN store_orderitem oi ON oi.product_id = p.id\n WHERE p.is_active = %s\n GROUP BY p.id ORDER BY order_count DESC LIMIT %s\n \"\"\"</span>,\n [<span>True</span>, <span>10</span>] <span># \u2190 always parameterized \u2014 NEVER string-format user input!</span>\n)\n\n<span># cursor \u2014 for non-model queries, reporting, analytics</span>\n<span>with</span> connection.<span>cursor</span>() <span>as</span> cursor:\n cursor.<span>execute</span>(<span>\"\"\"\n SELECT date_trunc('month', created_at) AS month,\n SUM(total) AS revenue\n FROM store_order\n GROUP BY 1 ORDER BY 1\n \"\"\"</span>)\n rows = cursor.<span>fetchall</span>()\n\n<span># NEVER do this \u2014 SQL injection!</span>\n<span># cursor.execute(f\"SELECT * FROM products WHERE name = '{user_input}'\")</span></code></pre></div>\n<h2>Signals \u2014 reacting to model events</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Django signals</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.db.models.signals <span>import</span> post_save, pre_delete\n<span>from</span> django.dispatch <span>import</span> receiver\n\n<span># Auto-create UserProfile when a User is created</span>\n<span>@receiver</span>(post_save, sender=<span>User</span>)\n<span>def</span> <span>create_user_profile</span>(sender, instance, created, **kwargs):\n <span>if</span> created:\n <span>UserProfile</span>.objects.<span>create</span>(user=instance)\n\n<span># Log deletions</span>\n<span>@receiver</span>(pre_delete, sender=<span>Product</span>)\n<span>def</span> <span>log_product_deletion</span>(sender, instance, **kwargs):\n <span>AuditLog</span>.objects.<span>create</span>(action=<span>'DELETE'</span>, model=<span>'Product'</span>, object_id=instance.id)\n\n<span># Signals available: pre_save, post_save, pre_delete, post_delete,</span>\n<span># m2m_changed, pre_migrate, post_migrate</span></code></pre></div>\n</section>\n<section data-section=\"\" id=\"admin\">\n<div class=\"section-header\"><div class=\"section-num\">12</div><div>\n<div class=\"section-title\">Admin Interface</div>\n<div class=\"section-subtitle\">Django's built-in database management UI \u2014 production-grade from day one</div>\n</div></div>\n<p>One of Django's most powerful features: a fully-featured admin UI generated from your models. Zero JavaScript required. Just register your models and Django builds the entire CRUD interface, search, filters, pagination, and bulk actions.</p>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">store/admin.py \u2014 fully customized</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.contrib <span>import</span> admin\n<span>from</span> .models <span>import</span> Product, Order, OrderItem\n\n<span># Inline \u2014 show OrderItems inside the Order edit page</span>\n<span>class</span> <span>OrderItemInline</span>(admin.<span>TabularInline</span>):\n model = <span>OrderItem</span>\n extra = <span>0</span>\n readonly_fields = [<span>'product'</span>, <span>'quantity'</span>, <span>'price_at_purchase'</span>]\n\n<span>@admin.register</span>(<span>Product</span>)\n<span>class</span> <span>ProductAdmin</span>(admin.<span>ModelAdmin</span>):\n list_display = [<span>'name'</span>, <span>'price'</span>, <span>'stock'</span>, <span>'is_active'</span>, <span>'created_at'</span>]\n list_display_links = [<span>'name'</span>]\n list_editable = [<span>'price'</span>, <span>'stock'</span>, <span>'is_active'</span>]\n search_fields = [<span>'name'</span>, <span>'description'</span>, <span>'slug'</span>]\n list_filter = [<span>'is_active'</span>, <span>'categories'</span>, <span>'created_at'</span>]\n prepopulated_fields = {<span>'slug'</span>: (<span>'name'</span>,)}\n readonly_fields = [<span>'created_at'</span>, <span>'updated_at'</span>]\n fieldsets = [\n (<span>None</span>, {<span>'fields'</span>: [<span>'name'</span>, <span>'slug'</span>, <span>'description'</span>]}),\n (<span>'Pricing'</span>, {<span>'fields'</span>: [<span>'price'</span>, <span>'stock'</span>]}),\n (<span>'Categorization'</span>, {<span>'fields'</span>: [<span>'categories'</span>]}),\n (<span>'Status'</span>, {<span>'fields'</span>: [<span>'is_active'</span>], <span>'classes'</span>: [<span>'collapse'</span>]}),\n (<span>'Metadata'</span>, {<span>'fields'</span>: [<span>'created_at'</span>, <span>'updated_at'</span>], <span>'classes'</span>: [<span>'collapse'</span>]}),\n ]\n actions = [<span>'activate_products'</span>, <span>'deactivate_products'</span>]\n\n <span>def</span> <span>activate_products</span>(self, request, queryset):\n updated = queryset.<span>update</span>(is_active=<span>True</span>)\n self.<span>message_user</span>(request, <span>f\"{updated} products activated.\"</span>)\n activate_products.short_description = <span>'Mark selected as active'</span>\n\n <span>def</span> <span>deactivate_products</span>(self, request, queryset):\n queryset.<span>update</span>(is_active=<span>False</span>)\n deactivate_products.short_description = <span>'Mark selected as inactive'</span>\n\n<span>@admin.register</span>(<span>Order</span>)\n<span>class</span> <span>OrderAdmin</span>(admin.<span>ModelAdmin</span>):\n inlines = [<span>OrderItemInline</span>]\n list_display = [<span>'id'</span>, <span>'user'</span>, <span>'status'</span>, <span>'total'</span>, <span>'created_at'</span>]\n list_filter = [<span>'status'</span>, <span>'created_at'</span>]\n search_fields = [<span>'user__username'</span>, <span>'user__email'</span>]\n raw_id_fields = [<span>'user'</span>] <span># use search widget for FK with many rows</span></code></pre></div>\n</section>\n<section data-section=\"\" id=\"views\">\n<div class=\"section-header\"><div class=\"section-num\">13</div><div>\n<div class=\"section-title\">Views &amp; URLs</div>\n<div class=\"section-subtitle\">Connecting HTTP requests to your business logic</div>\n</div></div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">config/urls.py \u2014 root router</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.contrib <span>import</span> admin\n<span>from</span> django.urls <span>import</span> path, include\n\nurlpatterns = [\n path(<span>'admin/'</span>, admin.site.urls),\n path(<span>'store/'</span>, include(<span>'store.urls'</span>)),\n path(<span>'api/'</span>, include(<span>'api.urls'</span>)),\n]</code></pre></div>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">store/urls.py + views.py</span><span class=\"code-lang\">python</span></div><pre><code><span># \u2500\u2500 store/urls.py \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>from</span> django.urls <span>import</span> path\n<span>from</span> . <span>import</span> views\n\nurlpatterns = [\n path(<span>''</span>, views.product_list, name=<span>'product-list'</span>),\n path(<span>'&lt;slug:slug&gt;/'</span>, views.product_detail, name=<span>'product-detail'</span>),\n path(<span>'&lt;int:pk&gt;/edit/'</span>, views.<span>ProductUpdateView</span>.as_view(), name=<span>'product-edit'</span>),\n path(<span>'create/'</span>, views.<span>ProductCreateView</span>.as_view(), name=<span>'product-create'</span>),\n]\n\n<span># \u2500\u2500 store/views.py \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>from</span> django.shortcuts <span>import</span> render, get_object_or_404\n<span>from</span> django.views.generic <span>import</span> CreateView, UpdateView\n<span>from</span> django.contrib.auth.mixins <span>import</span> LoginRequiredMixin\n<span>from</span> django.urls <span>import</span> reverse_lazy\n<span>from</span> .models <span>import</span> Product\n\n<span># \u2500\u2500 Function-Based View (FBV) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\n<span>def</span> <span>product_list</span>(request):\n category = request.GET.<span>get</span>(<span>'category'</span>)\n max_price = request.GET.<span>get</span>(<span>'max_price'</span>)\n\n products = <span>Product</span>.objects \\\n .<span>filter</span>(is_active=<span>True</span>) \\\n .<span>select_related</span>(<span>'main_category'</span>) \\\n .<span>prefetch_related</span>(<span>'categories'</span>)\n\n <span>if</span> category:\n products = products.<span>filter</span>(categories__slug=category)\n <span>if</span> max_price:\n products = products.<span>filter</span>(price__lte=max_price)\n\n <span>return</span> <span>render</span>(request, <span>'store/product_list.html'</span>, {\n <span>'products'</span>: products,\n <span>'count'</span>: products.<span>count</span>(),\n })\n\n<span>def</span> <span>product_detail</span>(request, slug):\n product = <span>get_object_or_404</span>(<span>Product</span>, slug=slug, is_active=<span>True</span>)\n <span>return</span> <span>render</span>(request, <span>'store/product_detail.html'</span>, {<span>'product'</span>: product})\n\n<span># \u2500\u2500 Class-Based View (CBV) \u2014 less code, more convention \u2500\u2500\u2500</span>\n<span>class</span> <span>ProductCreateView</span>(<span>LoginRequiredMixin</span>, <span>CreateView</span>):\n model = <span>Product</span>\n fields = [<span>'name'</span>, <span>'price'</span>, <span>'stock'</span>, <span>'description'</span>, <span>'categories'</span>]\n template_name = <span>'store/product_form.html'</span>\n success_url = <span>reverse_lazy</span>(<span>'product-list'</span>)\n\n<span>class</span> <span>ProductUpdateView</span>(<span>LoginRequiredMixin</span>, <span>UpdateView</span>):\n model = <span>Product</span>\n fields = [<span>'name'</span>, <span>'price'</span>, <span>'stock'</span>, <span>'description'</span>]\n template_name = <span>'store/product_form.html'</span>\n success_url = <span>reverse_lazy</span>(<span>'product-list'</span>)</code></pre></div>\n</section>\n<section data-section=\"\" id=\"performance\">\n<div class=\"section-header\"><div class=\"section-num\">14</div><div>\n<div class=\"section-title\">Performance &amp; Indexes</div>\n<div class=\"section-subtitle\">Making queries fast at scale \u2014 the complete toolkit</div>\n</div></div>\n<p>An index is a separate data structure PostgreSQL maintains alongside your table. Without an index on a column you filter by, PostgreSQL must scan every single row in the table \u2014 a sequential scan. At 1 million rows, that's the difference between 1ms and 300ms per query.</p>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">All Django index types</span><span class=\"code-lang\">python</span></div><pre><code><span>from</span> django.db.models <span>import</span> Index, Q\n<span>from</span> django.contrib.postgres.indexes <span>import</span> GinIndex, BrinIndex, SpGistIndex\n\n<span>class</span> <span>Product</span>(models.<span>Model</span>):\n <span>class</span> <span>Meta</span>:\n indexes = [\n\n <span># B-tree \u2014 default, general purpose, equality + range queries</span>\n <span>Index</span>(fields=[<span>'name'</span>], name=<span>'product_name_idx'</span>),\n\n <span># Composite \u2014 queries that filter on BOTH columns</span>\n <span>Index</span>(fields=[<span>'-created_at'</span>, <span>'is_active'</span>], name=<span>'product_list_idx'</span>),\n\n <span># Partial \u2014 only index active products (smaller, faster)</span>\n <span>Index</span>(\n fields=[<span>'price'</span>],\n name=<span>'product_active_price_idx'</span>,\n condition=<span>Q</span>(is_active=<span>True</span>),\n ),\n\n <span># GIN \u2014 for ArrayField, JSONField, full-text tsvector</span>\n <span>GinIndex</span>(fields=[<span>'tags'</span>], name=<span>'product_tags_gin'</span>),\n <span>GinIndex</span>(fields=[<span>'metadata'</span>], name=<span>'product_meta_gin'</span>),\n <span>GinIndex</span>(fields=[<span>'search_vector'</span>], name=<span>'product_search_gin'</span>),\n\n <span># BRIN \u2014 for time-series append-only tables (tiny index, huge tables)</span>\n <span>BrinIndex</span>(fields=[<span>'created_at'</span>], name=<span>'product_created_brin'</span>),\n ]</code></pre></div>\n<h2>Diagnosing slow queries</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">Query analysis tools</span><span class=\"code-lang\">python</span></div><pre><code><span># Print the SQL Django will generate (development)</span>\nqs = <span>Product</span>.objects.<span>filter</span>(is_active=<span>True</span>, price__lt=<span>100</span>)\nprint(str(qs.query))\n\n<span># In psql: EXPLAIN ANALYZE for the full query plan</span>\n<span># EXPLAIN ANALYZE SELECT * FROM store_products WHERE is_active = true AND price &lt; 100;</span>\n<span># Look for: \"Seq Scan\" (slow, needs an index) vs \"Index Scan\" (fast)</span>\n\n<span># Count queries in a code block</span>\n<span>from</span> django.test.utils <span>import</span> CaptureQueriesContext\n<span>from</span> django.db <span>import</span> connection\n<span>with</span> <span>CaptureQueriesContext</span>(connection) <span>as</span> ctx:\n <span>my_view_function</span>()\nprint(<span>f\"{len(ctx)} queries executed\"</span>) <span># if &gt; 10, investigate</span></code></pre></div>\n<div>\n<div class=\"tip-item\"><div class=\"ti-head\"> Use iterator()</div><p>For large querysets you loop once, use <code>.iterator(chunk_size=2000)</code> to stream results without caching all rows in memory. Saves RAM on big exports.</p></div>\n<div class=\"tip-item\"><div class=\"ti-head\"> Bulk operations</div><p>Use <code>bulk_create(objs, batch_size=1000)</code> and <code>bulk_update(objs, ['field'], batch_size=1000)</code> to insert/update thousands of rows in one query.</p></div>\n<div class=\"tip-item\"><div class=\"ti-head\"> update() over save()</div><p><code>Product.objects.filter(...).update(stock=0)</code> is one SQL UPDATE. Calling <code>product.save()</code> in a loop fires one query per object \u2014 never do that at scale.</p></div>\n<div class=\"tip-item\"><div class=\"ti-head\"> Connection pooling</div><p>In production, use PgBouncer or <code>django-db-geventpool</code>. Each Django process opens connections \u2014 without pooling you'll hit Postgres's <code>max_connections</code> limit quickly.</p></div>\n<div class=\"tip-item\"><div class=\"ti-head\"> fetch what you need</div><p>Use <code>.values()</code> or <code>.only()</code> in list endpoints. Don't fetch a 5MB <code>description</code> TextField when you only display the product name and price.</p></div>\n<div class=\"tip-item\"><div class=\"ti-head\"> Django Debug Toolbar</div><p>Install <code>django-debug-toolbar</code> in dev. It shows all SQL queries per request, their duration, and stacktrace origin. Finding N+1 bugs becomes trivial.</p></div>\n</div>\n</section>\n<section data-section=\"\" id=\"security\">\n<div class=\"section-header\"><div class=\"section-num\">15</div><div>\n<div class=\"section-title\">Security</div>\n<div class=\"section-subtitle\">What Django protects you from \u2014 and what you still need to handle</div>\n</div></div>\n<div class=\"cards\">\n<div class=\"card\"><div class=\"card-icon tone-success\"></div><h4>SQL Injection</h4><p>The ORM always uses parameterized queries \u2014 user input never goes directly into SQL. You're protected as long as you use the ORM. With raw SQL: always use <code>cursor.execute(\"... %s\", [value])</code>, never f-strings.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-info\"></div><h4>CSRF Protection</h4><p><code>CsrfViewMiddleware</code> requires a CSRF token on every POST/PUT/DELETE. The <code>{% csrf_token %}</code> template tag handles it. For APIs, use <code>@csrf_exempt</code> + token auth.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-tip\"></div><h4>Password Hashing</h4><p>Django hashes passwords with PBKDF2 (configurable to Argon2, bcrypt). Always use <code>user.set_password()</code>, never assign to <code>user.password</code> directly.</p></div>\n<div class=\"card\"><div class=\"card-icon tone-info\"></div><h4>XSS Prevention</h4><p>Django's template engine auto-escapes all HTML in <code>{{ variables }}</code>. Only use <code>{{ content|safe }}</code> when you are certain content is already sanitized.</p></div>\n</div>\n<h2>Production security checklist</h2>\n<div class=\"code-block\"><div class=\"code-header\"><span class=\"code-title\">config/settings_production.py</span><span class=\"code-lang\">python</span></div><pre><code><span># \u2500\u2500 Absolute requirements \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\nDEBUG = <span>False</span>\nALLOWED_HOSTS = [<span>'yourdomain.com'</span>, <span>'www.yourdomain.com'</span>]\nSECRET_KEY = config(<span>'SECRET_KEY'</span>) <span># long random string from .env</span>\n\n<span># \u2500\u2500 HTTPS enforcement \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\nSECURE_SSL_REDIRECT = <span>True</span>\nSECURE_HSTS_SECONDS = <span>31536000</span> <span># 1 year</span>\nSECURE_HSTS_INCLUDE_SUBDOMAINS = <span>True</span>\nSECURE_HSTS_PRELOAD = <span>True</span>\nSECURE_PROXY_SSL_HEADER = (<span>'HTTP_X_FORWARDED_PROTO'</span>, <span>'https'</span>)\n\n<span># \u2500\u2500 Cookie security \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\nSESSION_COOKIE_SECURE = <span>True</span> <span># HTTPS only</span>\nSESSION_COOKIE_HTTPONLY = <span>True</span> <span># no JS access</span>\nSESSION_COOKIE_SAMESITE = <span>'Lax'</span>\nCSRF_COOKIE_SECURE = <span>True</span>\n\n<span># \u2500\u2500 Content security \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\nSECURE_CONTENT_TYPE_NOSNIFF = <span>True</span>\nX_FRAME_OPTIONS = <span>'DENY'</span> <span># prevent clickjacking</span>\n\n<span># \u2500\u2500 Database \u2014 encrypted connection \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</span>\nDATABASES[<span>'default'</span>][<span>'CONN_MAX_AGE'</span>] = <span>60</span>\nDATABASES[<span>'default'</span>][<span>'OPTIONS'</span>][<span>'sslmode'</span>] = <span>'require'</span>\n\n<span># \u2500\u2500 Run Django's own security check</span>\n<span># python manage.py check --deploy</span></code></pre></div>\n<hr class=\"divider\"/>\n<div class=\"philosophy-block\">\n You now have a mental map of Django + PostgreSQL from first principles. The rest is practice. Build something real. Make mistakes. Read the error messages \u2014 Django's are among the most informative in any framework. The database is not your enemy; it is the ground your application stands on.\n <span>End of Guide \u2014 Go Build</span>\n</div>\n<div class=\"callout tone-info\"><div class=\"callout-label\"> What to read next</div><p><strong>Official Django docs</strong> \u2014 docs.djangoproject.com \u2014 especially the ORM reference, migrations guide, and the deployment checklist. <strong>PostgreSQL docs</strong> \u2014 postgresql.org/docs \u2014 chapters on indexes, EXPLAIN, and MVCC. Install <strong>django-debug-toolbar</strong> in every development project. It makes the ORM's SQL visible and N+1 bugs obvious.</p></div>\n</section>";

